	 email_id
	,email
	,recipient_nm
) values (
	 #{emailId}
	,#{email}
	,#{recipientNm}
)

/** CmmtEmailRecipientDao.insertList */
insert into cmmt_email_recipient (
	 email_id
	,email
	,recipient_nm
) values

	(
		 #{item.emailId}
		,#{item.email}
		,#{item.recipientNm}
	)

mapper.delete:
/** CmmtEmailRecipientDao.deleteList */
delete from
	cmmt_email_recipient
where
	email_id = #{emailId}

